#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUvOriginal;
vUv = (vUv-.5)*(1-ds/(1-GetBlur1(vUv).b)) + .5;
uv1 = (uv0-.5)*uAspect.xy*tele;
vec3 noise = fract(8*texture(sampler_noise_lq,vUv+rand_frame.yz));
   if (noise.g > .1)
   {
       vec3 noiseBiased = noise - vec3( 0.5, 0.5, 0.5 );
      //Eo.S. combine the subtraction on noise to a single vec3
      //to ensure compiler does the subtraction in a single ALU
      dist = MinDist( (noiseBiased.zy) * 0.000 + vUv ) +  0.01 * vec2((noiseBiased.x) * abs(noiseBiased.y), abs(noiseBiased.x) * (noiseBiased.y));
   }
   else {dist = noise.r;}
 dist = min(dist,GetDist(vUv)) - ds*.8;

limit = 80;
float tdist = dist + pow(dist,3)*.2;
uv2 = multiply(vec3(uv1*tdist,tdist-.0)/myzoom,RotMat)+CamPos;
uv2 = (fract(uv2/8.0+.5)-.5)*8.0;
box = mbox (uv2);
len = (length(box.xyz));
struc = length(box.xyz)/limit;

if ((len < limit) && (dist > 0.005)){
 ret.r = (1-sustain)*struc+sustain*(Get1(vUv).r); ret.gb=  PutDist(dist); }
 else {ret = texture(sampler_fw_main,fract(vUv))*vec3(.5*(sustain+1), (sustain), sustain) - .01*vec3((1 - sustain), 0, (1-sustain));}
//ret.r = struc;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float tele = q16;
vec2 uv0 = vUv;
vUv = vec2(abs(vUv.x-.5)+.5,vUv.y);
vUv = abs(vUv-.5)+.5;
vec3   ret2 = texture(sampler_main,vUv).xyz;

float blur1 = lum(GetPixel(vUv));
ret2 *= (.6 + .5*sin(vUv.x*10 + 3.14159265*(q27 + q28)));
ret2= mix(blur1,ret2,pow(ret2,.15+(audioMidSmooth)*.025));

vec2 uv1 = vUv-.5;
vec3 ret1 = texture(sampler_main, vUv) ;

const vec2 hor = vec2 (.0005,0);
const vec2 ver = vec2 (0,.0005);

float dx = GetPixel (vUv+hor*q21).r - GetPixel (vUv-hor*q21).b;
float dy = GetPixel (vUv+ver*q20).r - GetPixel (vUv-ver*q20).b;
vec2 dz = vec2 (dx,dy);

dz += (texture(sampler_noise_hq,uv1/((.5*q26 + .5*q27)/tele+vRadius)*(q23*.1 + q24*.1)+q31)-.5)*(.1);

uv1 = abs(uv1 - dz);
float dots = pow(abs(.03333/length(uv1)), .75);

ret1 = .7*ret1+dots*ret2*(5+sqrt(audioMid)*1);

vec3 ret3_1 = log(exp2(3.14159265*vec3((abs(q20) + abs(q21)), (abs(q21) + abs(q22)), (abs(q22) + abs(q20)))*ret1.gbr));
vec3 ret3_2 = log(exp2(3.14159265*vec3((abs(q23) + abs(q24)), (abs(q24) + abs(q25)), (abs(q25) + abs(q23)))*GetPixel(fract(-abs( reflect( fract(-uv1), fract(dz) ) ) )).rgb));
vec3 ret3_3 = log(exp2(3.14159265*vec3((abs(q26) + abs(q27)), (abs(q27) + abs(q28)), (abs(q28) + abs(q26)))*GetPixel( fract(-uv1) ).brg));

vec3 ret3 = mix(ret3_1, ret3_2, 1.5708 - acos(ret3_3) );

vec3 ret4 = mix(ret3_1, ret3_2, ret3_3);

vec3 ret5 = mix(1.5708 - acos(ret3_1), 1.5708 - acos(ret3_2), asin(ret3_3));

ret3 = abs(mix((1.5708 - acos(ret4)), (asin(ret3)), 3*q15*(ret5) ));

uv1 = vUv-.5 + .4*lum(GetPixel(vUv));
ret = .637*ret3 + exp(-20*(length(fract(lum(uv1)*3-uTime)-.5)))*q10 ;
//ret = ret5;

  fragColor = ret;
}
